CREATE TRIGGER LG_ORFLINE_UPD_099_01 ON LG_099_01_ORFLINE
FOR UPDATE
AS
DECLARE @LINETYPE         SMALLINT
DECLARE @STOCKREF         INT
DECLARE @LOGICALREF       INT
DECLARE @AMOUNT           FLOAT
DECLARE @ADDTAXAMOUNT     FLOAT
DECLARE @SHIPPEDAMOUNT    FLOAT
DECLARE @UINFO1           FLOAT
DECLARE @UINFO2           FLOAT
DECLARE @DT               DATETIME
DECLARE @DORESERVE        SMALLINT
DECLARE @RESERVEDT        DATETIME
DECLARE @CLOSED           SMALLINT
DECLARE @STATUS           SMALLINT
DECLARE @TRCODE           SMALLINT
DECLARE @SOURCEINDEX      SMALLINT
DECLARE @OFFTRREF         INT
DECLARE @OFFREF           INT
DECLARE @PREVLNREF        INT
DECLARE @DETLN            SMALLINT
DECLARE @PREVLNNO         SMALLINT
DECLARE @COEF             SMALLINT
DECLARE @CLREF              INT
DECLARE @REMAMOUNT          FLOAT
DECLARE @new_Status         SMALLINT
DECLARE @new_Trcode         SMALLINT
DECLARE @new_LINENET        FLOAT
DECLARE @new_REPORTRATE     FLOAT
DECLARE @new_BILLED         SMALLINT
DECLARE @old_Status         SMALLINT
DECLARE @old_Trcode         SMALLINT
DECLARE @old_LINENET        FLOAT
DECLARE @old_REPORTRATE     FLOAT
DECLARE @old_BILLED         SMALLINT
DECLARE @_Closed            SMALLINT
DECLARE @old_VATSTATE     SMALLINT
DECLARE @new_VATSTATE       SMALLINT
DECLARE @STRANS      SMALLINT
DECLARE @PROMOTION   SMALLINT
DECLARE @COMPOSITE   SMALLINT
DECLARE @SERVICE     SMALLINT
DECLARE @LCLASS      SMALLINT
DECLARE @VALID       SMALLINT
DECLARE @_OrdFICHEREF     INT
DECLARE @PRICE       FLOAT
DECLARE @DISTDISC    FLOAT
DECLARE @DISTEXP     FLOAT
DECLARE @DISTEXPVAT  FLOAT
DECLARE @VATAMNT     FLOAT
DECLARE @CANCELL     SMALLINT
DECLARE @DISTDISCVAT  FLOAT
DECLARE @DISTCOST    FLOAT
DECLARE @new_Stockref       INT
DECLARE @new_VariantRef     INT
DECLARE @new_PrevRef        INT
DECLARE @new_UomRef         INT
DECLARE @new_FactoryNr      INT
DECLARE @new_CancFlag       SMALLINT
DECLARE @new_Amount         FLOAT
DECLARE @new_SourceIndex    SMALLINT
DECLARE @new_ShippedAmount  FLOAT
DECLARE @new_ResrvAmount    FLOAT
DECLARE @new_DuDate         DATETIME
DECLARE @old_Stockref       INT
DECLARE @old_VariantRef     INT
DECLARE @old_PrevRef        INT
DECLARE @old_UomRef         INT
DECLARE @old_FactoryNr      INT
DECLARE @old_CancFlag       SMALLINT
DECLARE @old_Amount         FLOAT
DECLARE @old_SourceIndex    SMALLINT
DECLARE @old_ShippedAmount  FLOAT
DECLARE @old_ResrvAmount    FLOAT
DECLARE @old_DuDate         DATETIME
DECLARE @AFFECTCOLLTRL      SMALLINT
DECLARE @AFFECTRISK         SMALLINT
DECLARE @WITHPAYTRANS       SMALLINT
DECLARE @lNET               FLOAT
SELECT  @STRANS    = 0,
        @PROMOTION = 1,
        @SERVICE   = 4,
        @COMPOSITE = 6,
        @LCLASS    = 10,
 @VALID = 0
SELECT @_OrdFICHEREF   = I.ORDFICHEREF,
        @LINETYPE      = I.LINETYPE,
        @STOCKREF      = I.STOCKREF,
        @AMOUNT        = I.AMOUNT,
        @ADDTAXAMOUNT  = I.ADDTAXAMOUNT,
        @SHIPPEDAMOUNT = I.SHIPPEDAMOUNT,
        @UINFO1        = I.UINFO1,
        @UINFO2        = I.UINFO2,
        @DT            = I.DATE_,
        @DORESERVE     = I.DORESERVE,
        @RESERVEDT     = I.RESERVEDATE,
        @CLOSED        = I.CLOSED,
       @CANCELL       = I.CANCELLED,
        @STATUS        = I.STATUS,
        @TRCODE        = I.TRCODE,
        @SOURCEINDEX   = I.SOURCEINDEX,
        @new_VATSTATE  = I.VATINC,
        @LOGICALREF    = I.LOGICALREF,
 @REMAMOUNT = I.AMOUNT - I.SHIPPEDAMOUNT - I.SHIPPEDAMNTSUGG,
 @_Closed=I.CLOSED,
 @CLREF = I.CLIENTREF,
        @new_Status=I.STATUS,
        @new_TrCode = I.TRCODE,
        @new_ReportRate = I.REPORTRATE,
        @new_BILLED = I.BILLEDITEM,
        @PRICE=I.PRICE,
        @DISTDISC=I.DISTDISC ,
        @DISTEXP= I.DISTEXP,
        @DISTEXPVAT= I.DISTEXPVAT,
        @VATAMNT=I.VATAMNT,
        @OFFTRREF      = I.OFFTRANSREF,
        @OFFREF        = I.OFFERREF,
        @PREVLNREF     = I.PREVLINEREF,
        @DETLN         = I.DETLINE,
        @PREVLNNO      = I.PREVLINENO,
        @new_Stockref  = I.STOCKREF,
        @new_VariantRef= I.VARIANTREF,
        @new_PrevRef   = I.PREVLINEREF,
        @new_UomRef    = I.UOMREF,
        @new_FactoryNr = I.FACTORYNR,
        @new_CancFlag  = I.CANCELLED,
        @new_Amount    = I.AMOUNT,
        @new_SourceIndex = I.SOURCEINDEX,
        @new_ShippedAmount = I.SHIPPEDAMOUNT,
        @new_DuDate        = I.DUEDATE,
        @AFFECTCOLLTRL = I.AFFECTCOLLATRL,
        @AFFECTRISK    = I.AFFECTRISK,
        @WITHPAYTRANS  = I.WITHPAYTRANS,
        @new_ResrvAmount = I.RESERVEAMOUNT,
        @lNet = I.LINENET,
        @DISTDISCVAT= I.DISTDISCVAT,
        @DISTCOST = I.DISTCOST
FROM INSERTED I
IF @CANCELL=1
 BEGIN
  SELECT @CLOSED = 1
 END
EXECUTE LG_UPDATE_ORDTRANS_099_01 @LINETYPE, @STOCKREF, @new_VariantRef, @AMOUNT, @SHIPPEDAMOUNT, @UINFO1, @UINFO2,
                                  @DT, @DORESERVE, @RESERVEDT, @CLOSED, @STATUS, @TRCODE, @SOURCEINDEX,
                                  @OFFTRREF, @OFFREF, @PREVLNREF, @DETLN, @PREVLNNO, 1, 0
IF    ((@LINETYPE = @STRANS) OR (@LINETYPE = @COMPOSITE) OR (@LINETYPE = @SERVICE) OR (@LINETYPE = @LCLASS))
 SELECT @VALID = 1
IF @REMAMOUNT<0  set @REMAMOUNT=0
IF @DISTDISC IS NULL  SELECT @DISTDISC=0
IF @DISTEXP IS NULL SELECT @DISTEXP=0
IF @DISTEXPVAT IS NULL SELECT @DISTEXPVAT=0
IF @DISTDISCVAT IS NULL SELECT @DISTDISCVAT=0
IF @DISTCOST IS NULL  SELECT @DISTCOST=0
if @VALID=1
BEGIN
  SELECT @new_LINENET=(@lNet - @DISTDISC + @DISTEXP + @DISTCOST + @VATAMNT + @DISTEXPVAT + @ADDTAXAMOUNT + @DISTDISCVAT)/@AMOUNT*@REMAMOUNT
END
IF (@_Closed=0) AND (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (ISNULL(@AFFECTRISK,0)=0) AND (ISNULL(@WITHPAYTRANS,0)=0) AND (@VALID=1)
 EXECUTE LG_UPDATECLCARDRISKNUMS_099_01 @CLREF, @new_TRCODE, @new_LINENET, -1, @new_ReportRate, @new_BILLED, @new_Status, 0, 0
IF (@_Closed=0) AND (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (@AFFECTCOLLTRL=1)  AND (@VALID=1)
 EXECUTE LG_UPDCOLLATRLRISK_099_01 @CLREF, @new_TRCODE, @new_LINENET, -1, @new_ReportRate, @new_BILLED, @new_Status, 0, 0
SELECT
       @_OrdFICHEREF   = D.ORDFICHEREF,
       @LINETYPE      = D.LINETYPE,
       @STOCKREF      = D.STOCKREF,
       @AMOUNT        = D.AMOUNT,
       @ADDTAXAMOUNT  = D.ADDTAXAMOUNT,
       @SHIPPEDAMOUNT = D.SHIPPEDAMOUNT,
       @UINFO1        = D.UINFO1,
       @UINFO2        = D.UINFO2,
       @DT            = D.DATE_,
       @DORESERVE     = D.DORESERVE,
       @RESERVEDT     = D.RESERVEDATE,
       @CLOSED        = D.CLOSED,
       @CANCELL       = D.CANCELLED,
       @STATUS        = D.STATUS,
       @TRCODE        = D.TRCODE,
       @old_VATSTATE  = D.VATINC,
       @SOURCEINDEX   = D.SOURCEINDEX,
       @REMAMOUNT = D.AMOUNT - D.SHIPPEDAMOUNT - D.SHIPPEDAMNTSUGG, @_Closed = D.CLOSED,
       @CLREF = D.CLIENTREF,
       @old_Status=D.STATUS,
       @old_TrCode = D.TRCODE,
       @old_ReportRate = D.REPORTRATE,
       @old_BILLED = D.BILLEDITEM,
       @PRICE=D.PRICE,
       @DISTDISC=D.DISTDISC ,
       @DISTEXP= D.DISTEXP,
       @DISTEXPVAT= D.DISTEXPVAT,
       @VATAMNT=D.VATAMNT,
       @OFFTRREF      = D.OFFTRANSREF,
       @OFFREF        = D.OFFERREF,
       @PREVLNREF     = D.PREVLINEREF,
       @DETLN         = D.DETLINE,
       @PREVLNNO      = D.PREVLINENO,
       @old_Stockref  = D.STOCKREF,
       @old_VariantRef= D.VARIANTREF,
       @old_PrevRef   = D.PREVLINEREF,
       @old_UomRef    = D.UOMREF,
       @old_FactoryNr = D.FACTORYNR,
       @old_CancFlag  = D.CANCELLED,
       @old_Amount    = D.AMOUNT,
       @old_SourceIndex = D.SOURCEINDEX,
       @old_ShippedAmount = D.SHIPPEDAMOUNT,
       @old_DuDate        = D.DUEDATE,
       @AFFECTCOLLTRL = D.AFFECTCOLLATRL,
       @AFFECTRISK   = D.AFFECTRISK,
       @WITHPAYTRANS  = D.WITHPAYTRANS,
       @old_ResrvAmount = D.RESERVEAMOUNT,
       @lNet = D.LINENET,
       @DISTDISCVAT= D.DISTDISCVAT,
       @DISTCOST = D.DISTCOST
FROM DELETED D
IF @CANCELL=1
 BEGIN
  SELECT @CLOSED = 1
 END
EXECUTE LG_UPDATE_ORDTRANS_099_01 @LINETYPE, @STOCKREF, @old_VariantRef, @AMOUNT, @SHIPPEDAMOUNT, @UINFO1, @UINFO2,
                                  @DT, @DORESERVE, @RESERVEDT, @CLOSED, @STATUS, @TRCODE, @SOURCEINDEX,
                                  @OFFTRREF, @OFFREF, @PREVLNREF, @DETLN, @PREVLNNO, -1, 0
SELECT @VALID = 0
IF  ((@LINETYPE = @STRANS) OR (@LINETYPE = @COMPOSITE) OR (@LINETYPE = @SERVICE) OR (@LINETYPE = @LCLASS))
 SELECT @VALID = 1
IF @REMAMOUNT<0 set @REMAMOUNT=0
IF @DISTDISC IS NULL  SELECT @DISTDISC=0
IF @DISTEXP IS NULL SELECT @DISTEXP=0
IF @DISTEXPVAT IS NULL SELECT @DISTEXPVAT=0
IF @DISTDISCVAT IS NULL SELECT @DISTDISCVAT=0
IF @DISTCOST IS NULL  SELECT @DISTCOST=0
IF @VALID=1
BEGIN
 SELECT @old_LINENET=(@lNet - @DISTDISC + @DISTEXP + @DISTCOST + @VATAMNT + @DISTEXPVAT + @ADDTAXAMOUNT + @DISTDISCVAT) /@AMOUNT*@REMAMOUNT
END
IF (@_Closed=0) AND (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (ISNULL(@AFFECTRISK,0) = 0) AND (ISNULL(@WITHPAYTRANS,0)=0) AND (@VALID=1)
 EXECUTE LG_UPDATECLCARDRISKNUMS_099_01 @CLREF, @old_TRCODE, @old_LINENET, 1, @old_ReportRate, @old_BILLED, @old_Status, 0, 0
IF (@_Closed=0) AND (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (@AFFECTCOLLTRL=1)  AND (@VALID=1)
 EXECUTE LG_UPDCOLLATRLRISK_099_01 @CLREF, @old_TRCODE, @old_LINENET, 1, @old_ReportRate, @old_BILLED, @old_Status, 0, 0
IF (@new_UomRef <> @old_UomRef) OR (@new_Amount <> @old_Amount) OR
   (@new_SourceIndex <> @old_SourceIndex) OR
   (@new_FactoryNr <> @old_FactoryNr) OR (@new_CancFlag <> @old_CancFlag) OR
   (@new_ShippedAmount <> @old_ShippedAmount) OR (@new_Status <> @old_Status) OR
   (@new_DuDate <> @old_DuDate)
 EXECUTE LG_UPDATEMRPITMCHNG_099 @new_Stockref, @new_VariantRef, @new_PrevRef
IF (@new_Stockref <> @old_Stockref) OR (@new_VariantRef <> @old_VariantRef)
 BEGIN
      EXECUTE LG_UPDATEMRPITMCHNG_099 @new_Stockref, @new_VariantRef, @new_PrevRef
      EXECUTE LG_UPDATEMRPITMCHNG_099 @old_Stockref, @old_VariantRef, @old_PrevRef
 END
IF (@old_Amount <> @new_Amount) OR (@old_ResrvAmount <> @new_ResrvAmount)
 BEGIN
      EXECUTE LG_UPDSHIPPEDAMOUNTORD_099_01 @LOGICALREF
 END
